#!/usr/bin/env python3
"""mesh-shootout - latency + throughput across fat-station node configurations.

Measures what extra nodes do to (a) single-request forward latency and (b)
aggregate throughput under concurrent load, for the compute-split mesh: every
station holds the FULL knot and the `X-Layer-Range` header selects which layers
it runs (so this is compute distribution, not per-node memory sharding).

Stations are auto-discovered via /health; only configs whose stations are all up
are run. Override the endpoints with env vars:

  MESH_MAC   default http://127.0.0.1:8080   (fast reference node, role=both)
  MESH_R1A   default http://127.0.0.1:8090   (edge node, role=both)
  MESH_R1B   default http://127.0.0.1:8091   (edge node, role=both)

Each station must serve the SAME knot with role=both. Bring an R1 up with:
  adb -s <serial> shell 'cd /data/local/tmp && nohup ./fat-station \
      --knot qwen05-dense.knot --role both --layers 0..24 --port 8090 &'
  adb -s <serial> forward tcp:<localport> tcp:8090

Default test vector: qwen-0.5b "The capital of France is" -> argmax 12095
(" Paris"); every config must reproduce it or it is flagged.

Usage:
  python3 mesh-shootout.py [--runs N] [--requests K] [--concurrency C]
                           [--layers L] [--tokens a,b,c] [--expect ID]
"""
import argparse, os, struct, sys, time, urllib.request, urllib.error, statistics
from concurrent.futures import ThreadPoolExecutor

MAC = os.environ.get("MESH_MAC", "http://127.0.0.1:8080")
R1A = os.environ.get("MESH_R1A", "http://127.0.0.1:8090")
R1B = os.environ.get("MESH_R1B", "http://127.0.0.1:8091")


def post(base, path, body, headers):
    req = urllib.request.Request(base + path, data=body, method="POST")
    for k, v in headers.items():
        req.add_header(k, v)
    with urllib.request.urlopen(req, timeout=300) as r:
        return r.read()


def up(base):
    try:
        urllib.request.urlopen(base + "/health", timeout=4).read()
        return True
    except (urllib.error.URLError, OSError):
        return False


def to_f32(b):
    return struct.unpack("<%df" % (len(b) // 4), b)


def forward(tokens, seq, embed_node, cuts, head_node):
    """tokens -> embed -> chained /forward over `cuts` -> /lm-head; returns argmax."""
    body = struct.pack("<%dI" % len(tokens), *tokens)
    buf = post(embed_node, "/embed", body, {"X-Position": "0"})
    for node, lo, hi in cuts:
        buf = post(node, "/forward", buf,
                   {"X-Position": "0", "X-Sequence-Length": str(seq),
                    "X-Layer-Range": f"{lo}-{hi}"})
    logits = to_f32(post(head_node, "/lm-head", buf, {"X-Sequence-Length": str(seq)}))
    return max(range(len(logits)), key=lambda i: logits[i])


def even_cuts(nodes, layers):
    """Split [0, layers) evenly across nodes -> [(node, lo, hi), ...]."""
    n = len(nodes)
    return [(nodes[i], i * layers // n, (i + 1) * layers // n) for i in range(n)]


def build_configs(layers):
    have = {"Mac": MAC if up(MAC) else None,
            "R1a": R1A if up(R1A) else None,
            "R1b": R1B if up(R1B) else None}
    mac, r1a, r1b = have["Mac"], have["R1a"], have["R1b"]
    cfgs = []  # (name, embed_node, cuts, head_node)
    if mac:
        cfgs.append(("1 node  Mac only        (fast ref)", mac, [(mac, 0, layers)], mac))
    if r1a:
        cfgs.append(("1 node  R1 only         (edge   )", r1a, [(r1a, 0, layers)], r1a))
    if r1a and r1b:
        cfgs.append(("2 node  R1 + R1         (pipeline)", *(_e_h(even_cuts([r1a, r1b], layers)))))
    if mac and r1a:
        cfgs.append(("2 node  Mac + R1        (pipeline)", *(_e_h(even_cuts([mac, r1a], layers)))))
    if mac and r1a and r1b:
        cfgs.append(("3 node  Mac + R1 + R1   (pipeline)", *(_e_h(even_cuts([mac, r1a, r1b], layers)))))
    return cfgs, have


def _e_h(cuts):
    """(cuts) -> (embed_node, cuts, head_node) using first/last node in the chain."""
    return cuts[0][0], cuts, cuts[-1][0]


def main():
    ap = argparse.ArgumentParser(description="fat-station mesh latency + throughput shootout")
    ap.add_argument("--runs", type=int, default=6, help="latency runs per config (cold=1st, warm=median rest)")
    ap.add_argument("--requests", type=int, default=16, help="throughput total requests")
    ap.add_argument("--concurrency", type=int, default=4, help="throughput concurrent workers")
    ap.add_argument("--layers", type=int, default=24, help="model layer count to split")
    ap.add_argument("--tokens", default="785,6722,315,9625,374", help="prompt token ids")
    ap.add_argument("--expect", type=int, default=12095, help="expected argmax token id")
    args = ap.parse_args()

    tokens = [int(x) for x in args.tokens.split(",")]
    seq = len(tokens)
    cfgs, have = build_configs(args.layers)
    print("stations:", ", ".join(f"{k}={'up' if v else 'down'}" for k, v in have.items()))
    if not cfgs:
        print("no stations up - nothing to benchmark", file=sys.stderr)
        return 2
    print(f"test vector: tokens={tokens} expect={args.expect}  layers={args.layers}\n")

    print("== LATENCY  (single request) ==")
    print(f"{'config':<38} {'cold ms':>8} {'warm ms':>8} {'argmax':>7}")
    print("-" * 66)
    bad = 0
    for name, emb, cuts, head in cfgs:
        times, amax = [], None
        for _ in range(args.runs):
            t0 = time.time(); amax = forward(tokens, seq, emb, cuts, head); times.append((time.time() - t0) * 1000)
        cold, warm = times[0], statistics.median(times[1:]) if len(times) > 1 else times[0]
        flag = "" if amax == args.expect else "  <-- WRONG"
        bad += amax != args.expect
        print(f"{name:<38} {cold:>8.0f} {warm:>8.0f} {amax:>7}{flag}")

    print(f"\n== THROUGHPUT  PIPELINE  ({args.requests} requests @ {args.concurrency} concurrent) ==")
    print("   (layers split across nodes; stages can overlap across requests)")
    print(f"{'config':<38} {'req/s':>7} {'ms/req':>7} {'correct':>8}")
    print("-" * 66)
    for name, emb, cuts, head in cfgs:
        forward(tokens, seq, emb, cuts, head)  # warm
        t0 = time.time()
        with ThreadPoolExecutor(max_workers=args.concurrency) as ex:
            res = list(ex.map(lambda _: forward(tokens, seq, emb, cuts, head), range(args.requests)))
        dt = time.time() - t0
        ok = sum(1 for a in res if a == args.expect)
        print(f"{name:<38} {args.requests/dt:>7.2f} {dt/args.requests*1000:>7.0f} {ok:>5}/{args.requests}")

    # DATA-PARALLEL: each node is a full-model replica; whole requests are
    # round-robined across nodes. This is the throughput win the extra nodes
    # actually buy (no stage dependency -> near-linear scaling).
    nodes = [v for v in (have["R1a"], have["R1b"], have["Mac"]) if v]
    dp_sets = []
    if have["R1a"]:
        dp_sets.append(("1x R1            (baseline)", [have["R1a"]]))
    if have["R1a"] and have["R1b"]:
        dp_sets.append(("2x R1            data-parallel", [have["R1a"], have["R1b"]]))
    if len(nodes) >= 3:
        dp_sets.append(("3x Mac+R1+R1     data-parallel", nodes))
    print(f"\n== THROUGHPUT  DATA-PARALLEL  ({args.requests} requests @ {args.concurrency} concurrent) ==")
    print("   (each node a full replica; whole requests round-robined)")
    print(f"{'config':<38} {'req/s':>7} {'ms/req':>7} {'correct':>8}")
    print("-" * 66)
    for name, pool in dp_sets:
        for n in pool:
            forward(tokens, seq, n, [(n, 0, args.layers)], n)  # warm each replica
        t0 = time.time()
        with ThreadPoolExecutor(max_workers=args.concurrency) as ex:
            res = list(ex.map(lambda i: forward(tokens, seq, pool[i % len(pool)],
                                                [(pool[i % len(pool)], 0, args.layers)], pool[i % len(pool)]),
                              range(args.requests)))
        dt = time.time() - t0
        ok = sum(1 for a in res if a == args.expect)
        print(f"{name:<38} {args.requests/dt:>7.2f} {dt/args.requests*1000:>7.0f} {ok:>5}/{args.requests}")

    return 1 if bad else 0


if __name__ == "__main__":
    sys.exit(main())
